import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

const webhookTrigger = trigger({
  type: 'n8n-nodes-base.webhook',
  version: 2.1,
  config: {
    name: 'GET /list-tasks',
    parameters: {
      httpMethod: 'GET',
      path: 'list-tasks',
      responseMode: 'responseNode',
      options: {}
    }
  }
});

const readTasks = node({
  type: 'n8n-nodes-base.dataTable',
  version: 1.1,
  config: {
    name: 'Read Tasks',
    alwaysOutputData: true,
    parameters: {
      resource: 'row',
      operation: 'get',
      dataTableId: { __rl: true, mode: 'id', value: 'mxxIO5f6AzVSIuYr' },
      returnAll: true
    }
  }
});

const filterAndSort = node({
  type: 'n8n-nodes-base.code',
  version: 2,
  config: {
    name: 'Filter and Sort',
    parameters: {
      mode: 'runOnceForAllItems',
      jsCode: `
const items = $input.all();
const query = $('GET /list-tasks').first().json.query || {};
const priorityFilter = (query.priority || '').trim().toLowerCase();
const categoryFilter = (query.category || '').trim().toLowerCase();

let rows = items
  .map(item => item.json)
  .filter(row => Object.keys(row).length > 0);

if (priorityFilter) {
  rows = rows.filter(row => (row.priority || '').toLowerCase() === priorityFilter);
}

if (categoryFilter) {
  rows = rows.filter(row => (row.category || '').toLowerCase() === categoryFilter);
}

rows.sort((a, b) => {
  const dateA = new Date(a.created_at || 0).getTime();
  const dateB = new Date(b.created_at || 0).getTime();
  return dateB - dateA;
});

return [{ json: { tasks: rows } }];
`.trim()
    }
  }
});

const respond = node({
  type: 'n8n-nodes-base.respondToWebhook',
  version: 1.5,
  config: {
    name: 'Respond 200',
    parameters: {
      respondWith: 'json',
      responseBody: expr('{{ $json.tasks }}'),
      options: {
        responseCode: 200
      }
    }
  }
});

export default workflow('task-manager-list-tasks', 'Task Manager - List Tasks')
  .add(webhookTrigger)
  .to(readTasks)
  .to(filterAndSort)
  .to(respond);

