import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

// 1. Webhook trigger — POST /add-task
const webhookTrigger = trigger({
  type: 'n8n-nodes-base.webhook',
  version: 2.1,
  config: {
    name: 'POST /add-task',
    parameters: {
      httpMethod: 'POST',
      path: 'add-task',
      responseMode: 'responseNode',
      options: {}
    }
  }
});

// 2. Claude AI node — analyze task and return priority + category as JSON
const claudeAnalyze = node({
  type: '@n8n/n8n-nodes-langchain.anthropic',
  version: 1,
  config: {
    name: 'Claude - Analyze Task',
    parameters: {
      resource: 'text',
      operation: 'message',
      modelId: { __rl: true, mode: 'list', value: 'claude-opus-4-5' },
      messages: {
        values: [
          {
            role: 'user',
            content: expr(
              'Analyze the following task and return ONLY a valid JSON object with exactly two fields: "priority" (one of: "urgent", "high", "medium", "low") and "category" (a short free-form label such as "Work", "Health", "Finance", "Learning", "Personal", etc.).\n\nDo NOT include any markdown, code fences, explanation, or extra text. Return ONLY the raw JSON object.\n\nTask Title: {{ $json.body.title }}\nTask Description: {{ $json.body.description }}'
            )
          }
        ]
      },
      simplify: true,
      options: {
        maxTokens: 100,
        temperature: 0
      }
    },
    credentials: {
      anthropicApi: { id: '609q7ZROTvgTvuzV', name: 'Anthropic account' }
    }
  }
});

// 3. Code node — parse Claude's response and build full task record
const buildTaskRecord = node({
  type: 'n8n-nodes-base.code',
  version: 2,
  config: {
    name: 'Build Task Record',
    parameters: {
      mode: 'runOnceForAllItems',
      jsCode: `
const claudeItem = $input.first();

// Claude's text response is in the 'text' field when simplify=true
const rawText = claudeItem.json.text || claudeItem.json.content || '';

// Strip any accidental markdown fences
const cleaned = rawText.replace(/\`\`\`json/gi, '').replace(/\`\`\`/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: try to extract JSON object from the text
  const match = cleaned.match(/\\{[\\s\\S]*\\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    parsed = { priority: 'medium', category: 'General' };
  }
}

// Retrieve original webhook body from the trigger node
const webhookData = $('POST /add-task').first().json.body;

const task = {
  title: webhookData.title || '',
  description: webhookData.description || '',
  deadline: webhookData.deadline || '',
  priority: parsed.priority || 'medium',
  category: parsed.category || 'General',
  created_at: new Date().toISOString()
};

return [{ json: task }];
`.trim()
    }
  }
});

// 4. Data Table insert
const insertTask = node({
  type: 'n8n-nodes-base.dataTable',
  version: 1.1,
  config: {
    name: 'Insert Task',
    parameters: {
      resource: 'row',
      operation: 'insert',
      dataTableId: { __rl: true, mode: 'id', value: 'mxxIO5f6AzVSIuYr' },
      columns: {
        mappingMode: 'defineBelow',
        value: {
          title: expr('{{ $json.title }}'),
          description: expr('{{ $json.description }}'),
          deadline: expr('{{ $json.deadline }}'),
          priority: expr('{{ $json.priority }}'),
          category: expr('{{ $json.category }}'),
          created_at: expr('{{ $json.created_at }}')
        },
        schema: [
          { id: 'title', displayName: 'title', required: false, defaultMatch: false, display: true, type: 'string', canBeUsedToMatch: true },
          { id: 'description', displayName: 'description', required: false, defaultMatch: false, display: true, type: 'string', canBeUsedToMatch: false },
          { id: 'deadline', displayName: 'deadline', required: false, defaultMatch: false, display: true, type: 'string', canBeUsedToMatch: false },
          { id: 'priority', displayName: 'priority', required: false, defaultMatch: false, display: true, type: 'string', canBeUsedToMatch: false },
          { id: 'category', displayName: 'category', required: false, defaultMatch: false, display: true, type: 'string', canBeUsedToMatch: false },
          { id: 'created_at', displayName: 'created_at', required: false, defaultMatch: false, display: true, type: 'string', canBeUsedToMatch: false }
        ]
      },
      options: {}
    }
  }
});

// 5. Respond to Webhook — return the saved task record
const respondWithTask = node({
  type: 'n8n-nodes-base.respondToWebhook',
  version: 1.5,
  config: {
    name: 'Respond with Task',
    parameters: {
      respondWith: 'json',
      responseBody: expr('={{ $json }}'),
      options: {
        responseCode: 200
      }
    }
  }
});

export default workflow('task-manager-add-task', 'Task Manager - Add Task')
  .add(webhookTrigger)
  .to(claudeAnalyze)
  .to(buildTaskRecord)
  .to(insertTask)
  .to(respondWithTask);

