import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

// 1. Webhook trigger — GET at path calendar-events
const webhookTrigger = trigger({
  type: 'n8n-nodes-base.webhook',
  version: 2.1,
  config: {
    name: 'GET /calendar-events',
    parameters: {
      httpMethod: 'GET',
      path: 'calendar-events',
      responseMode: 'responseNode',
      options: {}
    }
  }
});

// 2. Code node — Calculate start and end of current week (Mon 00:00:00 to Sun 23:59:59)
const calcWeekRange = node({
  type: 'n8n-nodes-base.code',
  version: 2,
  config: {
    name: 'Calculate Week Range',
    parameters: {
      mode: 'runOnceForAllItems',
      jsCode: `
const now = new Date();
// Get day of week: 0=Sun, 1=Mon, ..., 6=Sat
const dayOfWeek = now.getDay();
// Days since Monday (treat Sunday as 6)
const daysSinceMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;

// Monday 00:00:00
const monday = new Date(now);
monday.setDate(now.getDate() - daysSinceMonday);
monday.setHours(0, 0, 0, 0);

// Sunday 23:59:59
const sunday = new Date(monday);
sunday.setDate(monday.getDate() + 6);
sunday.setHours(23, 59, 59, 999);

// Build ISO 8601 with timezone offset
function toISOWithOffset(date) {
  const pad = (n, len = 2) => String(n).padStart(len, '0');
  const tzOffset = -date.getTimezoneOffset();
  const sign = tzOffset >= 0 ? '+' : '-';
  const absOffset = Math.abs(tzOffset);
  const offsetHours = pad(Math.floor(absOffset / 60));
  const offsetMins = pad(absOffset % 60);
  const year = date.getFullYear();
  const month = pad(date.getMonth() + 1);
  const day = pad(date.getDate());
  const hours = pad(date.getHours());
  const mins = pad(date.getMinutes());
  const secs = pad(date.getSeconds());
  return \`\${year}-\${month}-\${day}T\${hours}:\${mins}:\${secs}\${sign}\${offsetHours}:\${offsetMins}\`;
}

return [{
  json: {
    weekStart: toISOWithOffset(monday),
    weekEnd: toISOWithOffset(sunday)
  }
}];
`.trim()
    }
  }
});

// 3. Google Calendar — fetch events from primary calendar for the week range
const fetchCalendarEvents = node({
  type: 'n8n-nodes-base.googleCalendar',
  version: 1.3,
  config: {
    name: 'Fetch Calendar Events',
    parameters: {
      resource: 'event',
      operation: 'getAll',
      calendar: { __rl: true, mode: 'id', value: 'primary' },
      returnAll: true,
      timeMin: expr('{{ $json.weekStart }}'),
      timeMax: expr('{{ $json.weekEnd }}'),
      options: {
        fields: 'items(id,summary,start,end)',
        singleEvents: true
      }
    },
    credentials: {
      googleCalendarOAuth2Api: { id: '5MjqGu3t0YdRw9uf', name: 'Google Calendar account' }
    }
  }
});

// 4. Code node — Map events into clean array { id, summary, start, end }
const mapEvents = node({
  type: 'n8n-nodes-base.code',
  version: 2,
  config: {
    name: 'Map Events',
    parameters: {
      mode: 'runOnceForAllItems',
      jsCode: `
const items = $input.all();
const events = items.map(item => {
  const e = item.json;
  // Handle all-day events (date only) vs timed events (dateTime)
  const startRaw = e.start || {};
  const endRaw = e.end || {};
  const start = startRaw.dateTime || startRaw.date || null;
  const end = endRaw.dateTime || endRaw.date || null;
  return {
    id: e.id || null,
    summary: e.summary || null,
    start,
    end
  };
});
return [{ json: { events } }];
`.trim()
    }
  }
});

// 5. Respond to Webhook — return 200 with events array as JSON
const respondWithEvents = node({
  type: 'n8n-nodes-base.respondToWebhook',
  version: 1.5,
  config: {
    name: 'Respond with Events',
    parameters: {
      respondWith: 'json',
      responseBody: expr('{{ $json.events }}'),
      options: {
        responseCode: 200
      }
    }
  }
});

export default workflow('task-manager-calendar-events', 'Task Manager - Calendar Events')
  .add(webhookTrigger)
  .to(calcWeekRange)
  .to(fetchCalendarEvents)
  .to(mapEvents)
  .to(respondWithEvents);

