=Analyze the following task and return ONLY a valid JSON object with exactly two fields: "priority" (one of: "urgent", "high", "medium", "low") and "category" (a short free-form label such as "Work", "Health", "Finance", "Learning", "Personal", etc.).

Do NOT include any markdown, code fences, explanation, or extra text. Return ONLY the raw JSON object.

Task Title: {{ $json.body.title }}
Task Description: {{ $json.body.description }}

parameters.jsCode:
const claudeItem = $input.first();

// Claude's text response is in the 'text' field when simplify=true
const rawText = claudeItem.json.text || claudeItem.json.content || '';

// Strip any accidental markdown fences
const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback: try to extract JSON object from the text
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  } else {
    parsed = { priority: 'medium', category: 'General' };
  }
}

// Retrieve original webhook body from the trigger node
const webhookData = $('POST /add-task').first().json.body;

const task = {
  title: webhookData.title || '',
  description: webhookData.description || '',
  deadline: webhookData.deadline || '',
  priority: parsed.priority || 'medium',
  category: parsed.category || 'General',
  created_at: new Date().toISOString()
};

return [{ json: task }];

parameterPatch.jsCode:
const claudeItem = $input.first();

// Claude node output: content is an array of {type, text} objects
let rawText = '';
if (typeof claudeItem.json.text === 'string') {
  rawText = claudeItem.json.text;
} else if (Array.isArray(claudeItem.json.content)) {
  rawText = claudeItem.json.content.map(c => c.text || '').join('');
} else if (typeof claudeItem.json.content === 'string') {
  rawText = claudeItem.json.content;
}

// Strip any accidental markdown fences
const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { parsed = JSON.parse(match[0]); } catch(e2) { parsed = {}; }
  } else {
    parsed = {};
  }
}

// Retrieve original webhook body from the trigger node
const webhookData = $('POST /add-task').first().json.body;

const task = {
  title: webhookData.title || '',
  description: webhookData.description || '',
  deadline: webhookData.deadline || '',
  priority: parsed.priority || 'medium',
  category: parsed.category || 'General',
  created_at: new Date().toISOString()
};

return [{ json: task }];

